      "path": "src/modules/members/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projects = {};

const addMemberToProject = (projectId, userId, role) => {
  if (!projects[projectId]) {
    return null;
  }

  const project = projects[projectId];
  if (project.members.some(member => member.userId === userId)) {
    return 'duplicate';
  }

  const newMember = { userId, role };
  project.members.push(newMember);
  return newMember;
};

const getProjectMembers = (projectId) => {
  if (!projects[projectId]) {
    return null;
  }
  return projects[projectId].members;
};

const setProjectsStore = (newProjects) => {
  projects = newProjects;
};

module.exports = { addMemberToProject, getProjectMembers, setProjectsStore };
