    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const taskService = require('./service');

router.post('/', (req, res) => {
  const { projectId } = req.params;
  const { title, description } = req.body;
  if (!title || !description) {
    return sendError(res, 400, 'invalid_task', 'Title and description are required');
  }

  const task = taskService.createTask(projectId, title, description);
  if (!task) {
    return sendError(res, 404, 'not_found', 'Project not found');
  }
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const { projectId } = req.params;
  const status = req.query.status;
  const tasks = taskService.getTasksByProjectId(projectId);
  if (!tasks) {
    return sendError(res, 404, 'not_found', 'Project not found');
  }

  let filteredTasks = tasks;
  if (status) {
    filteredTasks = tasks.filter(task => task.status === status);
  }
  res.json({ tasks: filteredTasks });
});

router.patch('/:taskId', (req, res) => {
  const { projectId, taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'invalid_status', 'Status must be todo or done');
  }

  const task = taskService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'not_found', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;
"
